(window.webpackJsonp=window.webpackJsonp||[]).push([[81],{344:function(v,_,t){"use strict";t.r(_);var p=t(13),a=Object(p.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"当退则退"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#当退则退"}},[v._v("#")]),v._v(" 当退则退")]),v._v(" "),_("h2",{attrs:{id:"未来的样子"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#未来的样子"}},[v._v("#")]),v._v(" 未来的样子")]),v._v(" "),_("p",[v._v("最近陆陆续续听说有不少兄弟已经离职了，相当一部分裸辞，没有找下家，准备回学校了。工作是一种煎熬，无论在哪莫不如此。上班如上坟，也不失为一种现实。")]),v._v(" "),_("p",[v._v("同事跟我说，人在哪里其实不重要，关键是要有一个你想去并且乐意去做的事。但是生活总会逼人面对现实，想做又乐意去做的事，大家都想做。")]),v._v(" "),_("p",[v._v("今天面试的时候，主管坦诚说其实一开始不想要我，感觉我有来镀金的嫌疑，这个部门需要扎扎实实干活的人，并且明确表示部门三地办公，暗示以后我混不下去要回南京随时可以。")]),v._v(" "),_("p",[v._v("突然觉得可能终究有一天还是会回南京去，上班的时候搭我妈的车到华为路下绕城，走两步到南研上班。然后找一个同样在南京的朋友结婚，过上好像公务员一样平平无奇的日子。年轻的时候可以到处去玩，但以后可能就累了，不想动了。")]),v._v(" "),_("p",[v._v("喜欢的古风歌手硕士毕业了，不过她也已经渐渐淡出了这个圈子。从浙大到北大，从工科到文科，从杭州到深圳，羡慕三跨考研的勇气，却自觉没有如此的实力。出名的古风歌手，尽是名校出身。足够的文化底蕴，才有带着仙气的作品，诚然如是。")]),v._v(" "),_("br"),v._v(" "),_("p",[v._v("心声社区看到一个帖子，问题还是老生常谈的问题：现在还在坚持生孩的是哪一批人。这个帖子不出意外引发了新一轮骂战，想生的人骂不想生的人不愿意承担义务，不想生的人骂想生的人思想顽固老古董。支持生育派占强势地位，从个人的懦弱躺平骂到违背人伦天道，再上升到国家民族，什么民族日薄西山，任人蹂躏，最后直接到了丧失作为生命体的资格。而反对生育派就只能说思想落后，辫子在心中、生了也不称职，永远把孩子当一个附属品。但总的来说，作为一个平均年薪起码50-60万的互联网社区，大部分人还是愿意去要孩子。这又一次说明了经济基础决定上层建筑，经济实力够的人多半还是想要个孩子继承家业。")]),v._v(" "),_("p",[v._v("上海海思的人又请我吃了顿饭，基本上是确定了要去了。目标是智慧视觉开发部，一个叠满了AI+芯片+视觉等各种热点领域buff的部门。不过蹭一堆热点buff对我一个底层垃圾来说意义不大，本质上我也不是为了蹭热度往里面凑，并且过去干的底软开发也不是很热点。地域上这个部门办公是三区分治，深圳为主，上海南京共同发展。既然大抵确定了离开深圳了，那么剩下的选择就是上海or南京。在另一个一线城市卷上几年，或者灰溜溜滚回去躺平。华为经过这么若干年的发展，已经很像一个国企了，可以干很久，甚至于只要选择降薪可以干到五六十。")]),v._v(" "),_("p",[v._v("知乎看到这样一段话：这个社会，没有什么阶层觉得自己饭碗是端稳的，农民怕灾，工人怕下岗，商人怕政策变动，现在又多了一个疫情，连中产和以上都有点朝不保夕的味道了。事实上这个国家从古到今都是这样，现在已经是千年难遇的好时候，但即便如此，很多人也是有生存焦虑的。中国人对于生存和稳定的渴望普遍太强烈，这种渴望甚至演变成为一种世世代代的焦虑。马斯洛需求层级里面，爱和尊重是第三层级的东西，温饱则是最底层级的生存权利，最底层级需求没解决，人是谈不到更高一个层级的需求的。相当一部分人中国女人，结婚的原动力不是什么爱情，而是披着爱情外衣的饥饿感，以及潜意识深处对饥饿的恐惧，也就是所谓的“嫁给面包”。这种恐惧甚至能相当程度上影响审美层面，把实际上最无趣和最不具备审美的一个群体，居然还给认同成了潮流。")]),v._v(" "),_("p",[v._v("然而我对稳定毫无兴趣，准确的说，对生存其实也没有多少兴趣。不太甘心躺平，却又没啥闯的力气。隔着无线网络扮演互联网成功人士，然而离开互联网身上一分钱都没有，线下一整个社恐了属于是，，，")]),v._v(" "),_("h2",{attrs:{id:"疫火重燃"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#疫火重燃"}},[v._v("#")]),v._v(" 疫火重燃")]),v._v(" "),_("p",[v._v("隔离生活=时间充分有保障的睡眠")]),v._v(" "),_("p",[v._v("以致于我因为睡的太多有点头疼")]),v._v(" "),_("p",[v._v("外卖一次比一次难吃")]),v._v(" "),_("p",[v._v("昨天点的腻的要死吃两口吃不下去了")]),v._v(" "),_("p",[v._v("今天干脆就是夹生饭")]),v._v(" "),_("br"),v._v(" "),_("p",[v._v("隔离生活=戾气很重总想找个群开喷")]),v._v(" "),_("p",[v._v("然而总不能对着有同事的群开喷")]),v._v(" "),_("p",[v._v("那么就只能去找找跟我没有利害关系的群")]),v._v(" "),_("p",[v._v("比如什么迎新群 什么电信科喷子群19款")]),v._v(" "),_("br"),v._v(" "),_("p",[v._v("隔离生活=网络差的要死啥也干不了")]),v._v(" "),_("p",[v._v("公司的远程办公代理开着贼占带宽")]),v._v(" "),_("p",[v._v("尤其是大家同时都在远程办公的时候")]),v._v(" "),_("p",[v._v("整个宽带可以说接近上不了网的状态")]),v._v(" "),_("br"),v._v(" "),_("p",[v._v("隔离生活=... 好在明天就要结束了")]),v._v(" "),_("p",[v._v("希望不要是一个新的疫情期的开始")]),v._v(" "),_("p",[v._v("就像上一次我被关在家里隔离的时候")]),v._v(" "),_("p",[v._v("是深圳疫情大爆发的开端一样，，，")]),v._v(" "),_("h2",{attrs:{id:"五年之前"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#五年之前"}},[v._v("#")]),v._v(" 五年之前")]),v._v(" "),_("p",[v._v("又到了一年一度填志愿的时候了，可我离高考已经过去五年了，逐渐淡忘了当年填志愿的时候的我是什么样子。当年的我还是太天真，不知道命运赐予我的每一分成绩，都在暗中标好了价格。北林与西南离我远去，而我到了牛头冲，学起了当年号称神中神的经济学专业。")]),v._v(" "),_("p",[v._v("后来的我踏上了转专业的道路，尽管电信科真的是压力很大，而且非常累，但我还是坚持了下来，还获得了一些成绩。不过，过去的东西终究是过去，我又未能保住这样的成绩，只能放任记忆凋零。作为学长的我，不能总沉浸在过去里，还得为后来的人指明道路和方向。")]),v._v(" "),_("p",[v._v("我曾经一度想要让后来人走上我走过的道路就行了，可大家的能力不一，需求也不尽相同。于是后来，我学会了倾听每一个学弟学妹的需要，结合他们自身的能力，尽力站在他们的角度上去想，给他们指点每一个他们可能遇上的坑，而不是把我的经历盲目的套用上去。")]),v._v(" "),_("p",[v._v("夕阳西下。在深圳唯美的暮色里，愿后来之人，一路安好！")]),v._v(" "),_("h2",{attrs:{id:"菊厂纪行·ii"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#菊厂纪行·ii"}},[v._v("#")]),v._v(" 菊厂纪行·II")]),v._v(" "),_("p",[v._v("2022年的上半年结束了。")]),v._v(" "),_("p",[v._v("半年过得很快，快到我感觉什么都没有干，就记得连绵不绝的疫情，还有不时的隔离。在H1熬过通宵，也看过凌晨四点的天亮。失去了热情，社畜生活也就这样。")]),v._v(" "),_("p",[v._v("工作几多迷茫，感情几度彷徨，现实几许忧伤，仍在等待天光。寻求转变，不过是一场自救。尽管下一个部门未必更好，但总归应当是不会更坏了。")]),v._v(" "),_("p",[v._v("回小时候待的地方看了看，发现其实也不怎么能看出来曾经的样子。记忆和现实终究互不相容，该尘封的东西就尘封吧。新一届的兄弟们也毕业了，回宣区送一送行。明年可能还有一次，但也可能这就是最后一次了。")]),v._v(" "),_("p",[v._v("熟悉的学弟出现在了我工位附近，一代新人终究要换掉旧人。后来者或许能获得他们想要的一切，但他们想要的一切，未必是我想要的。")]),v._v(" "),_("br"),v._v(" "),_("p",[v._v("悄无声息间，我在华为的生涯来到了第十二个月。十二个月里，国内油价一升涨了两块三毛四，飞机燃油附加费从零一步步涨到了两百。俄罗斯和乌克兰打起来了，打到现在两边都说自己赢了。恒大寄了，但又没有完全寄。若干房企排队暴雷，房价没涨也没跌，但没人买了。公务员一次一次降薪，某些地方的公务员甚至需要去卖房了。")]),v._v(" "),_("p",[v._v("疫情来了一波一波一波，各地的防疫生意越做越好。上海给大家展示了市场全面崩溃的下场，郑州给大家演示了政策的社会维稳功能。中概股全面崩盘，互联网大厂在惨淡的春天里批量毕业。大家都能看出是凛冬将至了，但大抵不会是烟花来咯，只能看见一些地方逐渐变得没有底线，祭典重现罢了。")]),v._v(" "),_("p",[v._v("中国人之所以活得很累，其实似乎是在于一种家族价值的东西在里面。由于东亚文明的长期内卷，家族价值远高于个人价值，大家更注重家族传承而非个人成就。师医公之所以是神，是因为他们可以为家族带来利益。而对于个人价值而言，师医公并没有太大意义。因此我觉得我与东亚文明的格格不入，大抵就在于家族这个东西于我的缺失。当我不需要考虑家族意义上的问题时，大部分人所努力的一切，对我来说都没有多少意义。")]),v._v(" "),_("p",[v._v("所以其实我也不知道我想做啥。")])])}),[],!1,null,null,null);_.default=a.exports}}]);